#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int main(){
    char *input = NULL;
    size_t len = 0;
    ssize_t read;
    while((read = getline(&input, &len, stdin)) != -1) {}
    if(!input) return 0;
    for(char *p = input; *p; ++p){
        if(p[0]=='\\' && p[1]=='n'){
            *p=' ';
            memmove(p+1, p+2, strlen(p+2)+1);
        }
    }
    char *token = strtok(input, " \t\n\r");
    if(!token) return 0;
    int T = atoi(token);
    const double PI = 3.1414;
    for(int i=0;i<T;++i){
        token = strtok(NULL, " \t\n\r");
        if(!token) break;
        double r = atof(token);
        double area = PI * r * r;
        printf("%.5f", area);
        if(i+1<T) printf("\\n");
    }
    free(input);
    return 0;
}

