        if (all[i] == '\\' && all[i+1] == 'n') {
            all[i] = ' ';
            all.erase(i+1,1);
        }
    }
    stringstream ss(all);
    int T; if(!(ss>>T)) return 0;
    const double PI = 3.1414;
    cout.setf(ios::fixed); cout<<setprecision(5);
    for(int i=0;i<T;++i){
        double r; if(!(ss>>r)) break;
        double area = PI * r * r;
        cout<<area;
        if(i+1<T) cout<<"\\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main{
    public static void main(String[] args) throws Exception{
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder raw = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            raw.append(line).append('\n');
        }
        for (int i = 0; i + 1 < raw.length(); i++) {
            if (raw.charAt(i) == '\\' && raw.charAt(i+1) == 'n') {
                raw.setCharAt(i, ' ');
                raw.deleteCharAt(i+1);
            }
        }
        StringTokenizer st = new StringTokenizer(raw.toString());
        if (!st.hasMoreTokens()) return;
        int T = Integer.parseInt(st.nextToken());
        final double PI = 3.1414;
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            if (!st.hasMoreTokens()) break;
            double r = Double.parseDouble(st.nextToken());
            double area = PI * r * r;
            sb.append(String.format(Locale.US, "%.5f", area));
            if (i + 1 < T) sb.append("\\n");
        }
        System.out.print(sb.toString());
    }
}

