import sys

def main():
    data = sys.stdin.read()
    if not data:
        return
    data = data.replace('\\n', ' ')
    tokens = data.split()
    if not tokens:
        return
    it = iter(tokens)
    T = int(next(it))
    PI = 3.1414
    out = []
    for _ in range(T):
        try:
            r = float(next(it))
        except StopIteration:
            break
        area = PI * r * r
        out.append(f"{area:.5f}")
    sys.stdout.write("\\n".join(out))

if __name__ == "__main__":
    main()

